        mk('fxFlame',g=>{ g.fillStyle(0xffffff,1); g.fillCircle(12,12,12); },24,24);
        mk('fxSmoke',g=>{ g.fillStyle(0xffffff,1); g.fillCircle(16,16,16); },32,32);
        mk('fxChunk',g=>{ g.fillStyle(0xffffff,1); g.fillRect(0,0,6,6); },6,6);
