      if(!this.textures.exists('fxCloud')){ const g=this.make.graphics({x:0,y:0,add:false}); for(let i=8;i>=1;i--){ g.fillStyle(0xffffff,0.05); g.fillCircle(32,32,i*4); } g.generateTexture('fxCloud',64,64); g.destroy(); }
